1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
15	const CURSED_SURCHARGE_PERCENT = 50;
16	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_PERCENT = 20;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
21	const PROCESSING_FEE = 5;
22	
23	const addSurchargePercent = (amount: number, percent: number): number =>
24	  (amount * (100 + percent)) / 100;
25	
26	const applyDiscountPercent = (amount: number, percent: number): number =>
27	  (amount * (100 - percent)) / 100;
28	
29	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
30	  condition ? addSurchargePercent(amount, percent) : amount;
31	
32	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
33	  condition ? applyDiscountPercent(amount, percent) : amount;
34	
35	const itemPremium = (item: Item): number => {
36	  const base = BASE_PREMIUMS[item.type];
37	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
38	  return addSurchargeIf(
39	    withCursed,
40	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
41	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
42	  );
43	};
44	
45	const sumItemPremiums = (items: Item[]): number =>
46	  items.reduce((sum, item) => sum + itemPremium(item), 0);
47	
48	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
49	  const itemsTotal = sumItemPremiums(items);
50	  const withContractAdjustment = isFirstQuote
51	    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
52	    : applyDiscountPercent(itemsTotal, REPEAT_CONTRACT_DISCOUNT_PERCENT);
53	  const withLoyalty = applyDiscountIf(
54	    withContractAdjustment,
55	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
56	    LOYALTY_DISCOUNT_PERCENT,
57	  );
58	  return withLoyalty + PROCESSING_FEE;
59	};
60	
61	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
62	  results: input.steps.map((step, index) => ({
63	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
64	  })),
65	});
